import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';
import * as XLSX from 'xlsx';
import { orgData, type Member, type Department } from '../data';
import { formatPhoneForDisplay } from './formatUtils';

type SectionKey = 'coordination' | 'program' | 'accommodation';

interface ExportSection {
  key: SectionKey;
  title: string;
  subtitle: string;
  color: [number, number, number];
  head: Member;
  auxiliaries: Member[];
  departments: Department[];
}

interface ExcelRow {
  Sección: string;
  Responsabilidad: string;
  Nombre: string;
  Cargo: string;
  Congregación: string;
  Teléfono: string;
  Email: string;
}

const COLORS = {
  white: [255, 255, 255] as [number, number, number],
  slate50: [248, 250, 252] as [number, number, number],
  slate100: [241, 245, 249] as [number, number, number],
  slate200: [226, 232, 240] as [number, number, number],
  slate300: [203, 213, 225] as [number, number, number],
  slate500: [100, 116, 139] as [number, number, number],
  slate600: [71, 85, 105] as [number, number, number],
  slate700: [51, 65, 85] as [number, number, number],
  slate800: [30, 41, 59] as [number, number, number],
  slate900: [15, 23, 42] as [number, number, number],
  blue: [37, 99, 235] as [number, number, number],
  indigo: [79, 70, 229] as [number, number, number],
  violet: [124, 58, 237] as [number, number, number],
  emerald: [5, 150, 105] as [number, number, number],
};

const PAGE = {
  w: 210,
  h: 297,
  mx: 12,
};

const COLISEO_B64 = '';

function safe(value?: string) {
  return (value ?? '').trim();
}

function setFill(doc: jsPDF, color: [number, number, number]) {
  doc.setFillColor(color[0], color[1], color[2]);
}

function setDraw(doc: jsPDF, color: [number, number, number]) {
  doc.setDrawColor(color[0], color[1], color[2]);
}

function setText(doc: jsPDF, color: [number, number, number]) {
  doc.setTextColor(color[0], color[1], color[2]);
}

function sectionColor(key: SectionKey): [number, number, number] {
  if (key === 'coordination') return COLORS.indigo;
  if (key === 'program') return COLORS.violet;
  return COLORS.emerald;
}

export function flattenOrgData(): ExportSection[] {
  const coordination = orgData.subDepartments?.find(d => d.name === 'Coordinación del Comité');
  const program = orgData.subDepartments?.find(d => d.name === 'Programa');
  const accommodation = orgData.subDepartments?.find(d => d.name === 'Alojamiento y Servicios');

  return [
    {
      key: 'coordination',
      title: 'Coordinación del Comité',
      subtitle: 'Departamentos bajo la Coordinación del Comité',
      color: sectionColor('coordination'),
      head: coordination!.head,
      auxiliaries: coordination?.head.auxiliaries ?? [],
      departments: coordination?.head.subDepartments ?? [],
    },
    {
      key: 'program',
      title: 'Programa',
      subtitle: 'Departamentos bajo la Superintendencia del Programa',
      color: sectionColor('program'),
      head: program!.head,
      auxiliaries: program?.head.auxiliaries ?? [],
      departments: program?.head.subDepartments ?? [],
    },
    {
      key: 'accommodation',
      title: 'Alojamiento',
      subtitle: 'Departamentos bajo la Superintendencia de Alojamiento',
      color: sectionColor('accommodation'),
      head: accommodation!.head,
      auxiliaries: accommodation?.head.auxiliaries ?? [],
      departments: accommodation?.head.subDepartments ?? [],
    },
  ];
}

function memberToExcelRow(section: string, responsibility: string, member: Member): ExcelRow {
  return {
    Sección: section,
    Responsabilidad: responsibility,
    Nombre: safe(member.name),
    Cargo: safe(member.role),
    Congregación: safe(member.congregation),
    Teléfono: formatPhoneForDisplay(member.phone),
    Email: safe(member.email),
  };
}

function flattenDepartmentForExcel(sectionTitle: string, department: Department): ExcelRow[] {
  const rows: ExcelRow[] = [];

  rows.push(memberToExcelRow(sectionTitle, department.name, department.head));

  department.head.auxiliaries?.forEach(aux => {
    rows.push(memberToExcelRow(sectionTitle, department.name, aux));
  });

  department.head.groups?.forEach(group => {
    group.members.forEach(member => {
      rows.push(memberToExcelRow(sectionTitle, `${department.name} - ${group.name}`, member));
    });
  });

  department.head.subDepartments?.forEach(subDept => {
    rows.push(...flattenDepartmentForExcel(sectionTitle, subDept));
  });

  return rows;
}

export async function exportToXlsx(sections: ExportSection[]) {
  const rows: ExcelRow[] = [];

  sections.forEach(section => {
    rows.push(memberToExcelRow('Comité de Asamblea', section.title, section.head));
    section.auxiliaries.forEach(aux => {
      rows.push(memberToExcelRow('Comité de Asamblea', section.title, aux));
    });
  });

  rows.push(memberToExcelRow('Presidencia', 'Presidencia', orgData));
  orgData.auxiliaries?.forEach(aux => {
    rows.push(memberToExcelRow('Presidencia', 'Presidencia', aux));
  });

  sections.forEach(section => {
    section.departments.forEach(dept => {
      rows.push(...flattenDepartmentForExcel(section.title, dept));
    });
  });

  const worksheet = XLSX.utils.json_to_sheet(rows);
  worksheet['!cols'] = [
    { wch: 24 },
    { wch: 30 },
    { wch: 28 },
    { wch: 28 },
    { wch: 24 },
    { wch: 18 },
    { wch: 30 },
  ];

  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, 'Organigrama');
  XLSX.writeFile(workbook, 'Organigrama_AR2026.xlsx');
}

function addFooter(doc: jsPDF) {
  const total = doc.getNumberOfPages();

  for (let i = 1; i <= total; i++) {
    doc.setPage(i);

    setFill(doc, COLORS.slate900);
    doc.rect(0, PAGE.h - 10, PAGE.w, 10, 'F');

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(8);
    setText(doc, COLORS.slate300);
    doc.text(`Página ${i}`, PAGE.mx, PAGE.h - 4);

    setText(doc, COLORS.slate500);
    doc.text('Organigrama Asamblea Regional 2026', PAGE.w / 2, PAGE.h - 4, { align: 'center' });
  }
}

function drawPageBackground(doc: jsPDF) {
  setFill(doc, COLORS.slate50);
  doc.rect(0, 0, PAGE.w, PAGE.h, 'F');
}

function drawTopBand(doc: jsPDF, title: string, color: [number, number, number]) {
  setFill(doc, color);
  doc.roundedRect(PAGE.mx, 10, PAGE.w - PAGE.mx * 2, 14, 4, 4, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(18);
  setText(doc, COLORS.white);
  doc.text(title, PAGE.mx + 6, 19);
}

function drawMiniPersonBlock(
  doc: jsPDF,
  x: number,
  y: number,
  w: number,
  label: string,
  member: Member,
  color: [number, number, number],
  showIcon: boolean = false
) {
  const h = 30;

  setFill(doc, COLORS.white);
  setDraw(doc, COLORS.slate200);
  doc.roundedRect(x, y, w, h, 4, 4, 'FD');

  setFill(doc, color);
  doc.roundedRect(x, y, w, 7, 4, 4, 'F');
  doc.rect(x, y + 3.5, w, 3.5, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8.5);
  setText(doc, COLORS.white);

  if (showIcon) {
    const iconSize = 2.8;
    drawDeptIcon(doc, label, x + 2.5, y + (7 - iconSize) / 2, iconSize);
    doc.text(label, x + 2.5 + iconSize + 1.2, y + 4.8);
  } else {
    doc.text(label, x + 4, y + 4.8);
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  setText(doc, COLORS.slate900);
  doc.text(safe(member.name), x + 4, y + 12.5);

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(7.6);
  setText(doc, COLORS.slate600);
  doc.text(safe(member.role), x + 4, y + 17.2);

  const line1 = [safe(member.congregation), formatPhoneForDisplay(member.phone)].filter(Boolean).join(' - ');
  const line2 = safe(member.email);

  if (line1) doc.text(line1, x + 4, y + 22.1);
  if (line2) doc.text(line2, x + 4, y + 26.4);
}

function drawCommitteeSectionCard(
  doc: jsPDF,
  x: number,
  y: number,
  w: number,
  section: ExportSection
) {
  const color = section.color;
  const aux = section.auxiliaries[0];
  // header(9) + sup block(32) + gap(3) + aux block(32) + bottom pad(4)
  const cardH = 9 + 32 + 3 + (aux ? 32 : 0) + 4;

  setFill(doc, COLORS.white);
  setDraw(doc, COLORS.slate200);
  doc.roundedRect(x, y, w, cardH, 5, 5, 'FD');

  setFill(doc, color);
  doc.roundedRect(x, y, w, 9, 5, 5, 'F');
  doc.rect(x, y + 4.5, w, 4.5, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(8.5);
  setText(doc, COLORS.white);
  doc.text(section.title, x + 3, y + 6);

  drawMiniPersonBlock(doc, x + 3, y + 12, w - 6, 'Superintendente', section.head, color);

  if (aux) {
    drawMiniPersonBlock(doc, x + 3, y + 12 + 32 + 3, w - 6, 'Auxiliar', aux, color);
  }
}

function drawPresidencyCard(doc: jsPDF, x: number, y: number, w: number) {
  const auxiliaries = orgData.auxiliaries ?? [];
  // Header(9) + one row of blocks(32) + bottom pad(4)
  const cardH = 9 + 32 + 4;
  const totalCols = 1 + auxiliaries.length;
  const colGap = 3;
  const colW = (w - 8 - colGap * (totalCols - 1)) / totalCols;

  setFill(doc, COLORS.white);
  setDraw(doc, COLORS.slate200);
  doc.roundedRect(x, y, w, cardH, 5, 5, 'FD');

  setFill(doc, COLORS.blue);
  doc.roundedRect(x, y, w, 9, 5, 5, 'F');
  doc.rect(x, y + 4.5, w, 4.5, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  setText(doc, COLORS.white);
  doc.text('PRESIDENCIA', x + 4, y + 6);

  drawMiniPersonBlock(doc, x + 4, y + 12, colW, 'Presidente', orgData, COLORS.blue);

  auxiliaries.forEach((aux, i) => {
    const bx = x + 4 + (colW + colGap) * (i + 1);
    drawMiniPersonBlock(doc, bx, y + 12, colW, 'Auxiliar del Presidente', aux, COLORS.blue);
  });
}

function drawVenueBlock(doc: jsPDF, x: number, y: number, w: number) {
  const imgH = 58;
  const cardH = imgH + 14; // image + label area

  // Outer card background
  setFill(doc, COLORS.slate800);
  setDraw(doc, COLORS.slate600);
  doc.roundedRect(x, y, w, cardH, 5, 5, 'FD');

  // Gradient-like top accent bar
  setFill(doc, COLORS.blue);
  doc.roundedRect(x, y, w, 4, 2, 2, 'F');
  doc.rect(x, y + 2, w, 2, 'F');

  // Image with rounded clip via tight inset
  const imgX = x + 3;
  const imgY = y + 6;
  const imgW = w - 6;

  // Subtle shadow rect behind image
  setFill(doc, COLORS.slate900);
  doc.roundedRect(imgX - 0.5, imgY - 0.5, imgW + 1, imgH + 1, 3, 3, 'F');

  try {
    doc.addImage(COLISEO_B64, 'JPEG', imgX, imgY, imgW, imgH, undefined, 'FAST');
  } catch (_) {
    // fallback: just the dark rect
  }

  // Caption strip at bottom
  setFill(doc, COLORS.slate900);
  doc.rect(x, y + cardH - 10, w, 10, 'F');
  doc.roundedRect(x, y + cardH - 10, w, 10, 0, 0, 'F');

  // Rounded bottom corners for caption
  setFill(doc, COLORS.slate900);
  doc.roundedRect(x, y + cardH - 6, w, 6, 3, 3, 'F');

  // Caption text
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  setText(doc, COLORS.white);
  doc.text('Coliseo de la Universidad de Medellín', PAGE.w / 2, y + cardH - 3.5, { align: 'center' });
}

function drawCoverPage(doc: jsPDF, sections: ExportSection[]) {
  drawPageBackground(doc);

  // ── Header band ──────────────────────────────────────────────────
  setFill(doc, COLORS.slate900);
  doc.rect(0, 0, PAGE.w, 34, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  setText(doc, COLORS.slate300);
  doc.text('ORGANIGRAMA', PAGE.mx, 10);

  doc.setFontSize(20);
  setText(doc, COLORS.white);
  doc.text('ASAMBLEA REGIONAL 2026', PAGE.mx, 18);

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(16);
  setText(doc, [191, 219, 254] as [number, number, number]);
  doc.text('Medellín 4', PAGE.mx, 25);

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(11);
  setText(doc, COLORS.slate300);
  doc.text('Felices para siempre', PAGE.mx, 31);

  const cardW = PAGE.w - PAGE.mx * 2;

  // ── COMITÉ DE ASAMBLEA (3 columns, top position) ─────────────────
  const labelMarginT = 10;
  const labelMarginB = 6;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(13);
  setText(doc, COLORS.slate900);
  doc.text('COMITÉ DE ASAMBLEA', PAGE.w / 2, 34 + labelMarginT + 6, { align: 'center' });

  const committeeY = 34 + labelMarginT + 6 + labelMarginB;
  const colGap = 4;
  const colW = (cardW - colGap * 2) / 3;
  const committeeCardH = 9 + 32 + 3 + 32 + 4;

  sections.forEach((section, i) => {
    const x = PAGE.mx + i * (colW + colGap);
    drawCommitteeSectionCard(doc, x, committeeY, colW, section);
  });

  const presidencyY = committeeY + committeeCardH + labelMarginT;

  // ── PRESIDENCIA (below the committee) ────────────────────────────
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(13);
  setText(doc, COLORS.slate900);
  doc.text('PRESIDENCIA', PAGE.w / 2, presidencyY + 6, { align: 'center' });

  drawPresidencyCard(doc, PAGE.mx, presidencyY + labelMarginB + 6, cardW);

  const presidencyCardH = 9 + 32 + 4;
  const venueY = presidencyY + labelMarginB + 6 + presidencyCardH + labelMarginT;

  // ── VENUE BLOCK ───────────────────────────────────────────────────
  drawVenueBlock(doc, PAGE.mx, venueY, cardW);
}

function drawSectionHeader(doc: jsPDF, section: ExportSection) {
  drawPageBackground(doc);
  drawTopBand(doc, section.title, section.color);

  const aux = section.auxiliaries[0];
  const colGap = 4;
  const fullW = PAGE.w - PAGE.mx * 2;
  const halfW = (fullW - colGap) / 2;

  if (aux) {
    drawMiniPersonBlock(doc, PAGE.mx, 30, halfW, 'Superintendente', section.head, section.color);
    drawMiniPersonBlock(doc, PAGE.mx + halfW + colGap, 30, halfW, 'Auxiliar', aux, section.color);
  } else {
    drawMiniPersonBlock(doc, PAGE.mx, 30, fullW, 'Superintendente', section.head, section.color);
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(10);
  setText(doc, COLORS.slate800);
  doc.text(section.subtitle, PAGE.mx, 66);
}

function drawModernDepartmentTable(
  doc: jsPDF,
  startY: number,
  title: string,
  rows: Array<{
    nombre: string;
    responsabilidad: string;
    congregacion: string;
    telefono: string;
    email: string;
  }>,
  color: [number, number, number]
) {
  setFill(doc, COLORS.white);
  setDraw(doc, COLORS.slate200);
  doc.roundedRect(PAGE.mx, startY, PAGE.w - PAGE.mx * 2, 8, 3, 3, 'FD');

  setFill(doc, color);
  doc.roundedRect(PAGE.mx, startY, PAGE.w - PAGE.mx * 2, 8, 3, 3, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9.5);
  setText(doc, COLORS.white);
  
  // Draw Icon
  const iconSize = 3.5;
  drawDeptIcon(doc, title, PAGE.mx + 4, startY + (8 - iconSize) / 2, iconSize);
  doc.text(title, PAGE.mx + 4 + iconSize + 1.5, startY + 5.3);

  autoTable(doc, {
    startY: startY + 10,
    margin: { left: PAGE.mx, right: PAGE.mx, bottom: 16 },
    head: [['Nombre', 'Responsabilidad', 'Congregación', 'Teléfono', 'Email']],
    body: rows.map(r => [
      r.nombre,
      r.responsabilidad,
      r.congregacion,
      r.telefono,
      r.email,
    ]),
    theme: 'plain',
    styles: {
      font: 'helvetica',
      fontSize: 7.5,
      cellPadding: { top: 2.3, right: 2.4, bottom: 2.3, left: 2.4 },
      textColor: COLORS.slate900,
      valign: 'middle',
      overflow: 'linebreak',
    },
    headStyles: {
      fillColor: COLORS.slate100,
      textColor: COLORS.slate800,
      fontStyle: 'bold',
    },
    alternateRowStyles: {
      fillColor: [250, 252, 255],
    },
    bodyStyles: {
      fillColor: COLORS.white,
    },
    tableLineWidth: 0,
    didParseCell: data => {
      if (data.section === 'head') {
        data.cell.styles.fillColor = COLORS.slate100;
      }
      if (data.section === 'body') {
        data.cell.styles.lineColor = COLORS.slate200;
        data.cell.styles.lineWidth = { bottom: 0.15 };
      }
    },
    columnStyles: {
      0: { cellWidth: 30 },
      1: { cellWidth: 40 },
      2: { cellWidth: 32 },
      3: { cellWidth: 24, halign: 'center' },
      4: { cellWidth: 56 },
    },
  });
}

function buildDepartmentRows(dept: Department) {
  const rows = [
    {
      nombre: safe(dept.head.name),
      responsabilidad: safe(dept.head.role),
      congregacion: safe(dept.head.congregation),
      telefono: formatPhoneForDisplay(dept.head.phone),
      email: safe(dept.head.email),
    },
  ];

  (dept.head.auxiliaries ?? []).forEach(aux => {
    rows.push({
      nombre: safe(aux.name),
      responsabilidad: safe(aux.role),
      congregacion: safe(aux.congregation),
      telefono: formatPhoneForDisplay(aux.phone),
      email: safe(aux.email),
    });
  });

  return rows;
}

function drawCoordinationPage(doc: jsPDF, section: ExportSection) {
  doc.addPage();
  drawSectionHeader(doc, section);

  let y = 72;
  let isNewPage = false;

  section.departments.forEach(dept => {
    // Force new page before Primeros Auxilios
    if (dept.name === 'Primeros Auxilios' && !isNewPage) {
      doc.addPage();
      drawPageBackground(doc);
      y = 14;
      isNewPage = true;
    }
    drawModernDepartmentTable(doc, y, dept.name, buildDepartmentRows(dept), section.color);
    // @ts-expect-error plugin property
    y = doc.lastAutoTable.finalY + 4;
  });
}

function drawProgramPage(doc: jsPDF, section: ExportSection) {
  doc.addPage();
  drawSectionHeader(doc, section);

  let y = 72;

  const av = section.departments.find(d => d.name === 'Audio y Video');
  const bautismo = section.departments.find(d => d.name === 'Bautismo');

  if (av) {
    const groups = av.head.groups ?? [];
    const colGap = 3;
    const colW = (PAGE.w - PAGE.mx * 2 - colGap * 3) / 4;

    const getGroup = (name: string) => {
      const g = groups.find(gr => gr.name === name);
      if (!g || g.members.length === 0) {
        return {
          head: { name: 'Sin asignar', role: '', congregation: '', phone: '', email: '' } as Member,
          aux: [] as Member[],
        };
      }
      return {
        head: g.members[0],
        aux: g.members.slice(1),
      };
    };

    const audio = getGroup('Audio');
    const video = getGroup('Video');
    const plataforma = getGroup('Plataforma');
    const jwStream = getGroup('JW Stream');

    // Card principal pequeña y centrada para James Villamizar
    const parentW = 96;
    const parentX = (PAGE.w - parentW) / 2;
    const parentY = y;

    drawMiniPersonBlock(doc, parentX, parentY, parentW, 'Audio y Video', av.head, section.color, true);

    // Cards hijas
    const audioX = PAGE.mx;
    const videoX = PAGE.mx + colW + colGap;
    const plataformaX = PAGE.mx + (colW + colGap) * 2;
    const jwStreamX = PAGE.mx + (colW + colGap) * 3;
    const childY = parentY + 42;

    // Conectores
    const parentCenterX = parentX + parentW / 2;
    const parentBottomY = parentY + 30;
    const connectorTopY = parentBottomY + 4;
    const connectorLineY = childY - 6;
    const audioCenterX = audioX + colW / 2;
    const videoCenterX = videoX + colW / 2;
    const plataformaCenterX = plataformaX + colW / 2;
    const jwStreamCenterX = jwStreamX + colW / 2;

    setDraw(doc, COLORS.slate300);
    doc.setLineWidth(0.6);
    doc.line(parentCenterX, parentBottomY, parentCenterX, connectorTopY);
    doc.line(audioCenterX, connectorLineY, jwStreamCenterX, connectorLineY);
    doc.line(parentCenterX, connectorTopY, parentCenterX, connectorLineY);
    doc.line(audioCenterX, connectorLineY, audioCenterX, childY);
    doc.line(videoCenterX, connectorLineY, videoCenterX, childY);
    doc.line(plataformaCenterX, connectorLineY, plataformaCenterX, childY);
    doc.line(jwStreamCenterX, connectorLineY, jwStreamCenterX, childY);

    drawMiniPersonBlock(doc, audioX, childY, colW, 'Audio', audio.head, section.color, true);
    drawMiniPersonBlock(doc, videoX, childY, colW, 'Video', video.head, section.color, true);
    drawMiniPersonBlock(doc, plataformaX, childY, colW, 'Plataforma', plataforma.head, section.color, true);
    drawMiniPersonBlock(doc, jwStreamX, childY, colW, 'JW Stream', jwStream.head, section.color, true);

    y = childY + 34;

    // Draw auxiliaries as full rows in a single combined table per group
    const buildGroupAuxRows = (members: Member[], groupLabel: string) =>
      members.map(m => ({
        nombre: safe(m.name),
        responsabilidad: `Auxiliar ${groupLabel}`,
        congregacion: safe(m.congregation),
        telefono: formatPhoneForDisplay(m.phone),
        email: safe(m.email),
      }));

    const allAuxRows = [
      ...buildGroupAuxRows(audio.aux, 'Audio'),
      ...buildGroupAuxRows(video.aux, 'Video'),
      ...buildGroupAuxRows(plataforma.aux, 'Plataforma'),
      ...buildGroupAuxRows(jwStream.aux, 'JW Stream'),
    ];

    if (allAuxRows.length > 0) {
      drawModernDepartmentTable(doc, y, 'Auxiliares — Audio, Video, Plataforma y JW Stream', allAuxRows, section.color);
      // @ts-expect-error plugin property
      y = doc.lastAutoTable.finalY + 4;
    } else {
      y += 10;
    }
  }

  if (bautismo) {
    drawModernDepartmentTable(doc, y, 'Bautismo', buildDepartmentRows(bautismo), section.color);
  }
}

function drawAccommodationPage(doc: jsPDF, section: ExportSection) {
  doc.addPage();
  drawSectionHeader(doc, section);

  let y = 72;
  let isNewPage = false;

  section.departments.forEach(dept => {
    // Force new page before Objetos Perdidos y Guardarropa
    if (dept.name === 'Objetos Perdidos y Guardarropa' && !isNewPage) {
      doc.addPage();
      drawPageBackground(doc);
      y = 14;
      isNewPage = true;
    }
    drawModernDepartmentTable(doc, y, dept.name, buildDepartmentRows(dept), section.color);
    // @ts-expect-error plugin property
    y = doc.lastAutoTable.finalY + 4;
  });
}

export async function exportToPdf(sections: ExportSection[]) {
  const doc = new jsPDF({
    unit: 'mm',
    format: 'a4',
    compress: true,
  });

  drawCoverPage(doc, sections);
  drawCoordinationPage(doc, sections[0]);
  drawProgramPage(doc, sections[1]);
  drawAccommodationPage(doc, sections[2]);
  addFooter(doc);

  doc.save('Organigrama_AR2026.pdf');
}

// --- PDF ICON UTILITIES ---

function drawDeptIcon(doc: jsPDF, name: string, x: number, y: number, size: number) {
  const n = name.toLowerCase();

  doc.setDrawColor(255, 255, 255);
  doc.setFillColor(255, 255, 255);
  doc.setLineWidth(Math.max(0.18, size * 0.06));

  const midX = x + size / 2;
  const midY = y + size / 2;

  const line = (x1: number, y1: number, x2: number, y2: number) => {
    doc.line(x1, y1, x2, y2);
  };

  const rect = (rx: number, ry: number, rw: number, rh: number, style: 'S' | 'F' | 'FD' = 'S') => {
    doc.rect(rx, ry, rw, rh, style);
  };

  const rounded = (rx: number, ry: number, rw: number, rh: number, r = 0.35, style: 'S' | 'F' | 'FD' = 'S') => {
    doc.roundedRect(rx, ry, rw, rh, r, r, style);
  };

  const circle = (cx: number, cy: number, r: number, style: 'S' | 'F' | 'FD' = 'S') => {
    doc.circle(cx, cy, r, style);
  };

  const ellipse = (cx: number, cy: number, rx: number, ry: number, style: 'S' | 'F' | 'FD' = 'S') => {
    doc.ellipse(cx, cy, rx, ry, style);
  };

  try {
    // AUDIO Y VIDEO
    if (n.includes('audio') || n.includes('video')) {
      rounded(x + size * 0.1, y + size * 0.25, size * 0.45, size * 0.4, 0.2, 'S');
      doc.triangle(x + size * 0.6, midY, x + size * 0.85, y + size * 0.2, x + size * 0.85, y + size * 0.8, 'S');
      return;
    }

    // ACOMODADORES
    if (n.includes('acomodador')) {
      circle(x + size * 0.3, y + size * 0.3, size * 0.12, 'F');
      circle(x + size * 0.7, y + size * 0.3, size * 0.12, 'F');
      ellipse(x + size * 0.3, y + size * 0.75, size * 0.2, size * 0.1, 'F');
      ellipse(x + size * 0.7, y + size * 0.75, size * 0.2, size * 0.1, 'F');
      return;
    }

    // SEGURIDAD
    if (n.includes('seguridad')) {
      line(midX, y + size * 0.1, x + size * 0.8, y + size * 0.3);
      line(x + size * 0.8, y + size * 0.3, x + size * 0.8, y + size * 0.7);
      line(x + size * 0.8, y + size * 0.7, midX, y + size * 0.9);
      line(midX, y + size * 0.9, x + size * 0.2, y + size * 0.7);
      line(x + size * 0.2, y + size * 0.7, x + size * 0.2, y + size * 0.3);
      line(x + size * 0.2, y + size * 0.3, midX, y + size * 0.1);
      return;
    }

    // PLATAFORMA
    if (n.includes('plataforma')) {
      rounded(x + size * 0.1, y + size * 0.2, size * 0.8, size * 0.5, 0.2, 'S');
      rect(midX - size * 0.05, y + size * 0.7, size * 0.1, size * 0.15, 'F');
      line(x + size * 0.25, y + size * 0.85, x + size * 0.75, y + size * 0.85);
      return;
    }

    // JW STREAM
    if (n.includes('stream')) {
      circle(midX, midY, size * 0.1, 'F');
      circle(midX, midY, size * 0.25, 'S');
      circle(midX, midY, size * 0.4, 'S');
      return;
    }

    // INFORMACIÓN / SERVICIO VOLUNTARIO
    if (n.includes('información') || n.includes('informacion') || n.includes('servicio voluntario')) {
      circle(midX, midY, size * 0.45, 'S');
      circle(midX, y + size * 0.3, size * 0.06, 'F');
      rect(midX - size * 0.04, y + size * 0.45, size * 0.08, size * 0.3, 'F');
      return;
    }

    // ALOJAMIENTO
    if (n.includes('alojamiento')) {
      rect(x + size * 0.15, y + size * 0.5, size * 0.7, size * 0.1, 'F');
      rect(x + size * 0.15, y + size * 0.3, size * 0.25, size * 0.2, 'F');
      line(x + size * 0.15, y + size * 0.25, x + size * 0.15, y + size * 0.85);
      line(x + size * 0.85, y + size * 0.45, x + size * 0.85, y + size * 0.85);
      return;
    }

    // LIMPIEZA
    if (n.includes('limpieza')) {
      line(midX, y, midX, y + size);
      line(x, midY, x + size, midY);
      line(x + size * 0.2, y + size * 0.2, x + size * 0.8, y + size * 0.8);
      line(x + size * 0.8, y + size * 0.2, x + size * 0.2, y + size * 0.8);
      return;
    }

    // PRIMEROS AUXILIOS
    if (n.includes('primeros auxilios')) {
      rect(midX - size * 0.12, y + size * 0.1, size * 0.24, size * 0.8, 'F');
      rect(x + size * 0.1, midY - size * 0.12, size * 0.8, size * 0.24, 'F');
      return;
    }

    // BAUTISMO
    if (n.includes('bautismo')) {
      circle(midX, y + size * 0.65, size * 0.25, 'F');
      doc.triangle(midX, y + size * 0.15, x + size * 0.27, y + size * 0.6, x + size * 0.73, y + size * 0.6, 'F');
      return;
    }

    // OBJETOS PERDIDOS / GUARDARROPA
    if (n.includes('objetos perdidos') || n.includes('guardarropa')) {
      rounded(x + size * 0.15, y + size * 0.35, size * 0.7, size * 0.45, 0.2, 'S');
      rect(x + size * 0.35, y + size * 0.2, size * 0.3, size * 0.15, 'S');
      line(x + size * 0.15, y + size * 0.55, x + size * 0.85, y + size * 0.55);
      return;
    }

    // TRANSPORTE / MATERIALES
    if (n.includes('transporte') || n.includes('materiales')) {
      rect(x + size * 0.1, y + size * 0.4, size * 0.5, size * 0.3, 'F');
      rect(x + size * 0.6, y + size * 0.45, size * 0.25, size * 0.25, 'F');
      circle(x + size * 0.3, y + size * 0.8, size * 0.1, 'F');
      circle(x + size * 0.7, y + size * 0.8, size * 0.1, 'F');
      return;
    }

    // INSTALACIÓN
    if (n.includes('instalación') || n.includes('instalacion')) {
      line(x + size * 0.2, y + size * 0.8, x + size * 0.8, y + size * 0.2);
      circle(x + size * 0.2, y + size * 0.8, size * 0.08, 'F');
      line(x + size * 0.6, y + size * 0.1, x + size * 0.9, y + size * 0.4);
      return;
    }

    // ESTACIONAMIENTO
    if (n.includes('estacionamiento')) {
      rounded(x + size * 0.2, y + size * 0.4, size * 0.6, size * 0.3, 0.2, 'F');
      circle(x + size * 0.35, y + size * 0.75, size * 0.1, 'F');
      circle(x + size * 0.65, y + size * 0.75, size * 0.1, 'F');
      return;
    }

    // CONTABILIDAD
    if (n.includes('contabilidad')) {
      rect(x + size * 0.2, y + size * 0.1, size * 0.6, size * 0.8, 'S');
      line(x + size * 0.3, y + size * 0.3, x + size * 0.7, y + size * 0.3);
      line(x + size * 0.3, y + size * 0.5, x + size * 0.7, y + size * 0.5);
      line(x + size * 0.3, y + size * 0.7, x + size * 0.5, y + size * 0.7);
      return;
    }

    // DEFAULT
    circle(midX, y + size * 0.32, size * 0.18, 'F');
    ellipse(midX, y + size * 0.8, size * 0.32, size * 0.15, 'F');

  } catch {
    circle(midX, midY, size * 0.1, 'F');
  }
}